import anthropic

client = anthropic.Anthropic()

# Example: well-designed tool definitions for a code agent
tools = [
    {
        "name": "read_file",
        "description": (
            "Read the complete contents of a file from the local filesystem. "
            "Use this to understand existing code before making changes. "
            "Returns the file content as a string. "
            "Returns an error if the file does not exist."
        ),
        "input_schema": {
            "type": "object",
            "properties": {
                "path": {
                    "type": "string",
                    "description": "Absolute path to the file (e.g., /home/user/project/src/main.py)"
                },
                "start_line": {
                    "type": "integer",
                    "description": "Optional: start reading from this line number (1-indexed). Omit to read from beginning."
                },
                "end_line": {
                    "type": "integer",
                    "description": "Optional: stop reading at this line number (inclusive). Omit to read to end of file."
                }
            },
            "required": ["path"]
        }
    },
    {
        "name": "search_in_files",
        "description": (
            "Search for a pattern (regex or exact string) across files in a directory. "
            "Use this to find where a function is defined, all usages of an import, "
            "or all files containing a specific identifier. "
            "Returns: list of {file, line_number, line_content} matches. "
            "Use read_file to get context around a match."
        ),
        "input_schema": {
            "type": "object",
            "properties": {
                "pattern": {
                    "type": "string",
                    "description": "The search pattern (supports Python regex syntax)"
                },
                "directory": {
                    "type": "string",
                    "description": "Directory to search in (searches recursively)"
                },
                "file_pattern": {
                    "type": "string",
                    "description": "Optional glob pattern to restrict which files are searched (e.g., '*.py', '*.ts')"
                },
                "max_results": {
                    "type": "integer",
                    "description": "Maximum number of results to return (default: 50)",
                    "default": 50
                }
            },
            "required": ["pattern", "directory"]
        }
    },
    {
        "name": "edit_file",
        "description": (
            "Make a precise string replacement in a file. "
            "The old_string must match EXACTLY (including whitespace and indentation). "
            "The replacement is applied exactly once — old_string must appear exactly once in the file. "
            "Always read_file first to confirm the exact content before editing. "
            "Returns: success message or error if old_string not found."
        ),
        "input_schema": {
            "type": "object",
            "properties": {
                "path": {
                    "type": "string",
                    "description": "Absolute path to the file to edit"
                },
                "old_string": {
                    "type": "string",
                    "description": "The exact text to replace (must appear exactly once in the file)"
                },
                "new_string": {
                    "type": "string",
                    "description": "The text to replace old_string with"
                }
            },
            "required": ["path", "old_string", "new_string"]
        }
    },
    {
        "name": "run_command",
        "description": (
            "Execute a shell command and return stdout and stderr. "
            "Use for: running tests, linting, building, installing packages, checking git status. "
            "Do NOT use for: long-running servers, interactive commands, or commands requiring user input. "
            "Commands time out after 60 seconds. "
            "Returns: {stdout, stderr, exit_code, timed_out}"
        ),
        "input_schema": {
            "type": "object",
            "properties": {
                "command": {
                    "type": "string",
                    "description": "The shell command to execute"
                },
                "working_directory": {
                    "type": "string",
                    "description": "Directory to run the command in (defaults to project root)"
                },
                "timeout_seconds": {
                    "type": "integer",
                    "description": "Command timeout in seconds (default: 60, max: 120)",
                    "default": 60
                }
            },
            "required": ["command"]
        }
    }
]

# Example: sending tools with a message
response = client.messages.create(
    model="claude-sonnet-4-5",
    max_tokens=4096,
    tools=tools,
    messages=[
        {"role": "user", "content": "Find all usages of the authenticate() function and add error logging"}
    ]
)

print(f"Stop reason: {response.stop_reason}")
if response.stop_reason == "tool_use":
    for block in response.content:
        if block.type == "tool_use":
            print(f"Tool called: {block.name}")
            print(f"Input: {block.input}")
